//$Id$
//customNote.js
export * from './annotationRenderer';
import { annotation } from './annotation';
import { invokeFunction } from '../utils/zcutils';
import { d3_select } from '../core/d3-constants';
import { $Browser } from '../core/browser-detect';
import { renderDom } from '../mark/dom-render';

annotation.customNote = function() {
    var conf, coordinate, chartObj;

    function annotationComp(selection) {
        selection.each(function(args) {
            d3_select(this).each(() => {
                let thisElement = d3_select(this);

                if (conf.parser && !(!args.conf.parser && args.conf.htmlEl)) {
                    let parser = invokeFunction(conf.parser, chartObj, args.conf || conf);
                    renderDom(parser, thisElement);
                    chartObj._annotation = parser; // TODO: check
                    return;
                }

                let customContent = invokeFunction(conf.htmlEl, chartObj, args.conf || conf);

                if (customContent && (customContent.isD3Selection || customContent.nodeType === 1)) {
                    thisElement.html(''); // remove everything
                    let el = customContent.isD3Selection ? customContent.node() : customContent;
                    if (el.nodeType === 1) {
                        this.appendChild($Browser.IE ? el.cloneNode(true) : el); // ZC2382
                    }
                } else {
                    thisElement.html(customContent);
                }
            });
        });
    }
    annotationComp.coordinate = function(_) {
        if (!arguments.length) {
            return coordinate;
        }
        coordinate = _;
        return annotationComp;
    };
    annotationComp.conf = function(_) {
        if (!arguments.length) {
            return conf;
        }
        conf = _;
        return annotationComp;
    };
    annotationComp.chartObj = function(_) {
        if (!arguments.length) {
            return chartObj;
        }
        chartObj = _;
        return annotationComp;
    };
    return annotationComp;
};

export var _customAnnotation = annotation.customNote;
